static void
radix3_t1_oop_dit_fwd_scalar(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ W_re, const double * __restrict__ W_im,
    size_t is, size_t os, size_t me)
{
    const double KHALF = 0.500000000000000000000000000000000000000000000;
    const double KS    = 0.866025403784438596588302061718422919511795044;

    double x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    for (size_t m = mb; m < me; m++) {
        x0_re = in_re[m+0*is]; x0_im = in_im[m+0*is];
        x1_re = in_re[m+1*is]; x1_im = in_im[m+1*is];
        x2_re = in_re[m+2*is]; x2_im = in_im[m+2*is];
        { double wr = W_re[0*me+m], wi = W_im[0*me+m], tr = x1_re;
          x1_re = x1_re*wr - x1_im*wi;
          x1_im = tr*wi + x1_im*wr; }
        { double wr = W_re[1*me+m], wi = W_im[1*me+m], tr = x2_re;
          x2_re = x2_re*wr - x2_im*wi;
          x2_im = tr*wi + x2_im*wr; }

        /* DFT-3 butterfly [fwd] */
        double ar=(x1_re)+(x2_re), ai=(x1_im)+(x2_im);
        double dr=(x1_re)-(x2_re), di=(x1_im)-(x2_im);
        double R1r=(x0_re)-(KHALF)*(ar), R1i=(x0_im)-(KHALF)*(ai);
        x0_re=(x0_re)+(ar); x0_im=(x0_im)+(ai);
        x1_re=(KS)*(di)+(R1r); x1_im=(R1i)-(KS)*(dr);
        x2_re=(R1r)-(KS)*(di); x2_im=(KS)*(dr)+(R1i);

        out_re[m+0*os] = x0_re; out_im[m+0*os] = x0_im;
        out_re[m+1*os] = x1_re; out_im[m+1*os] = x1_im;
        out_re[m+2*os] = x2_re; out_im[m+2*os] = x2_im;
    }
}

